                  <div className="p-2 bg-vitta-accent-bg text-vitta-accent rounded-xl">
                    <ShieldCheck size={20} />
                  </div>
                  <div>
                    <p className="font-bold text-sm text-vitta-text-primary">
                      Autenticação em Duas Etapas (2FA)
                    </p>
