  useEffect(() => {
    let unsubscribeUserData: (() => void) | null = null;

    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      // Unsubscribe from any previous user snapshot listener to avoid memory leaks or unauthorized background reads on logout/user change
      if (unsubscribeUserData) {
        unsubscribeUserData();
        unsubscribeUserData = null;
      }

      setUser(firebaseUser);

      if (firebaseUser) {
        // Listen to user data in real-time
        unsubscribeUserData = onSnapshot(
          doc(db, "users", firebaseUser.uid),
          async (snapshot) => {
            if (snapshot.exists()) {
              const data = snapshot.data();
              setUserData(data);

              const isAdminEmail =
                data.email &&
                (data.email === "jhecksanto@gmail.com" ||
                  data.email === "admin@vitta.club" ||
                  data.email === "suporte@vitta.club");

              if (isAdminEmail && data.role !== "admin") {
                console.log("DEBUG: Elevating user to admin role in database...");
                await updateDoc(doc(db, "users", firebaseUser.uid), {
                  role: "admin",
                });
              } else if (data.email && !isAdminEmail) {
                // Check if user's email belongs to a registered professional
                try {
                  const qProf = query(
                    collection(db, "professionals"),
                    where("email", "==", data.email),
                  );
                  const profSnap = await getDocs(qProf);
                  if (!profSnap.empty) {
                    const profDoc = profSnap.docs[0];
                    // If role is not professional or userId is not matched, link them in background
                    if (data.role !== "professional") {
                      await updateDoc(doc(db, "users", firebaseUser.uid), {
                        role: "professional",
                      });
                    }
                    if (profDoc.data().userId !== firebaseUser.uid) {
                      await updateDoc(doc(db, "professionals", profDoc.id), {
                        userId: firebaseUser.uid,
                      });
                    }
                  }
                } catch (err) {
                  console.error(
                    "Erro ao verificar vinculo de profissional:",
                    err,
                  );
                }
              }
            } else {
              // Create if missing
              const isUserAdmin =
                firebaseUser.email === "jhecksanto@gmail.com" ||
                firebaseUser.email === "admin@vitta.club" ||
                firebaseUser.email === "suporte@vitta.club";

              const newData: any = {
                uid: firebaseUser.uid,
                name: firebaseUser.displayName || "Usuário",
                email: firebaseUser.email,
                role: isUserAdmin ? "admin" : "user",
                status: "Ativo",
                plan: isUserAdmin ? "Infinity" : "Free",
                createdAt: Timestamp.now(),
              };

              // Also check on initial creation if this user is a professional or liberal professional by email
              if (firebaseUser.email && !isUserAdmin) {
                try {
                  const qProf = query(
                    collection(db, "professionals"),
                    where("email", "==", firebaseUser.email),
                  );
                  const profSnap = await getDocs(qProf);
                  if (!profSnap.empty) {
                    newData.role = "professional";
                    const profDoc = profSnap.docs[0];
                    newData.feeRate = profDoc.data().feeRate !== undefined ? Number(profDoc.data().feeRate) : 0;
                    setTimeout(async () => {
                      try {
                        await updateDoc(doc(db, "professionals", profDoc.id), {
                          userId: firebaseUser.uid,
                        });
                      } catch (e) {
                        console.error(
                          "Erro ao vincular id do profissional na criacao:",
                          e,
                        );
                      }
                    }, 1000);
                  } else {
                    const qLib = query(
                      collection(db, "liberal_professionals"),
                      where("email", "==", firebaseUser.email),
                    );
                    const libSnap = await getDocs(qLib);
                    if (!libSnap.empty) {
                      newData.role = "liberal";
                      const libDoc = libSnap.docs[0];
                      newData.feeRate = libDoc.data().feeRate !== undefined ? Number(libDoc.data().feeRate) : 0;
                      setTimeout(async () => {
                        try {
                          await updateDoc(doc(db, "liberal_professionals", libDoc.id), {
                            userId: firebaseUser.uid,
                          });
                        } catch (e) {
                          console.error(
                            "Erro ao vincular id do profissional liberal na criacao:",
                            e,
                          );
                        }
                      }, 1000);
                    }
                  }
                } catch (err) {
                  console.error(err);
                }
              }
              await setDoc(doc(db, "users", firebaseUser.uid), newData);
              setUserData(newData);
            }
            setIsAuthReady(true);
          },
          (error) => {
            handleFirestoreError(
              error,
              OperationType.GET,
              `users/${firebaseUser.uid}`,
            );
            setIsAuthReady(true);
          },
        );
      } else {
        setUserData(null);
        setIsAuthReady(true);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubscribeUserData) unsubscribeUserData();
    };
  }, []);

  useEffect(() => {
    if (!isAuthReady || !user || !userData) return;

    const checkRoomDeepLink = async () => {
      const roomParam = new URLSearchParams(window.location.search).get("room");
      if (!roomParam) return;

      try {
        const aptDoc = await getDoc(doc(db, "appointments", roomParam));
        if (aptDoc.exists()) {
          const aptData = { id: aptDoc.id, ...aptDoc.data() } as any;

          // 1. Check completed/cancelled status
          if (aptData.status === "completed" || aptData.status === "cancelled") {
            addToast("Esta consulta de telemedicina já foi encerrada ou expirou.", "error");
          } else {
            // 2. Clearances or security check
            const isPatient = aptData.userId === user.uid || (aptData.patientEmail && aptData.patientEmail === user.email);
            const isProfessional = aptData.professionalUserId === user.uid || (userData.role === "professional" && userData.id === aptData.professionalId) || (aptData.professionalEmail && aptData.professionalEmail === user.email);

            if (isPatient || isProfessional) {
              setActiveTelemedicineApt(aptData);
              addToast("Bem-vindo(a) à sala de telemedicina segura!", "success");
            } else {
              addToast("Acesso negado: você não tem permissão para acessar esta consulta médica confidencial.", "error");
            }
          }
        } else {
          addToast("Erro: Sala de telemedicina não localizada ou inválida.", "error");
        }
      } catch (error) {
        console.error("Error processing deep link room:", error);
        addToast("Erro ao processar convite de telemedicina.", "error");
      } finally {
        // Clean up URL parameter to maintain elegant state and routing
        const url = new URL(window.location.href);
        url.searchParams.delete("room");
        window.history.replaceState({}, document.title, url.pathname + url.search);
      }
    };

    checkRoomDeepLink();
  }, [isAuthReady, user, userData]);

